window.HK_LC5 = {"q12": [{"n": 1, "part": 1, "q": "", "qko": "", "opts": ["A man is cutting a vegetable.", "A man is rinsing a knife in the sink.", "A man is taking a utensil from a drawer.", "A man is folding an apron."], "optko": ["한 남자가 채소를 자르고 있다.", "한 남자가 싱크대에서 칼을 씻고 있다.", "한 남자가 서랍에서 주방용품을 꺼내고 있다.", "한 남자가 앞치마를 접고 있다."], "ans": 0, "audio": "Test05_01.mp3", "img": "hk_t5_q1.jpg"}, {"n": 2, "part": 1, "q": "", "qko": "", "opts": ["She is wiping a counter with a cloth.", "She is serving some customers.", "She is reaching for a ladder.", "She is studying something in her hand."], "optko": ["그녀는 천으로 계산대를 닦고 있다.", "그녀는 고객들을 돕고 있다.", "그녀는 사다리를 향해 손을 뻗고 있다.", "그녀는 손에 있는 무언가를 보고 있다."], "ans": 3, "audio": "Test05_02.mp3", "img": "hk_t5_q2.jpg"}, {"n": 3, "part": 1, "q": "", "qko": "", "opts": ["They are adjusting a microscope.", "They are pouring liquid into a dish.", "They are wearing lab coats.", "They are seated across from each other."], "optko": ["그들은 현미경을 조정하고 있다.", "그들은 접시에 액체를 따르고 있다.", "그들은 실험실 가운을 입고 있다.", "그들은 서로의 맞은편에 앉아 있다."], "ans": 2, "audio": "Test05_03.mp3", "img": "hk_t5_q3.jpg"}, {"n": 4, "part": 1, "q": "", "qko": "", "opts": ["Some papers are being printed.", "The man is pushing up his sleeves.", "The shelf is behind the man.", "An apple is being cut."], "optko": ["문서가 인쇄되고 있다.", "남자가 소매를 걷어 올리고 있다.", "선반이 남자의 뒤에 있다.", "사과가 잘라지고 있다."], "ans": 2, "audio": "Test05_04.mp3", "img": "hk_t5_q4.jpg"}, {"n": 5, "part": 1, "q": "", "qko": "", "opts": ["Some cabin roofs are being repaired.", "Camping gear has been loaded into a truck.", "Tents have been set up on a lawn.", "Some leaves have been raked into a pile."], "optko": ["오두막집 지붕들이 수리되고 있다.", "캠핑 장비가 트럭에 실어져 있다.", "텐트들이 잔디 위에 세워져 있다.", "나뭇잎들이 갈퀴로 긁어모아 쌓여 있다."], "ans": 2, "audio": "Test05_05.mp3", "img": "hk_t5_q5.jpg"}, {"n": 6, "part": 1, "q": "", "qko": "", "opts": ["The woman is filling up a gas tank.", "The woman has tied back her hair.", "The woman is removing a car tire.", "The woman is opening the hood of a car."], "optko": ["여자가 연료 탱크를 채우고 있다.", "여자가 머리를 뒤로 묶어 놓았다.", "여자가 자동차의 타이어를 떼어내고 있다.", "여자가 자동차의 보닛을 열고 있다."], "ans": 1, "audio": "Test05_06.mp3", "img": "hk_t5_q6.jpg"}, {"n": 7, "part": 2, "q": "When did you arrive at the airport?", "qko": "당신은 언제 공항에 도착했나요?", "opts": ["Yes, I sent it yesterday.", "An hour before my departure.", "At the international terminal."], "optko": ["네, 저는 어제 그것을 보냈어요.", "출발 한 시간 전이요.", "국제선 터미널에서요."], "ans": 1, "audio": "Test05_07.mp3"}, {"n": 8, "part": 2, "q": "Why don't you sign up for a tour of the stadium?", "qko": "경기장 견학을 신청하는 게 어떤가요?", "opts": ["I already did.", "A concert at the stadium.", "He works as a tour guide."], "optko": ["저는 이미 했어요.", "경기장에서의 콘서트요.", "그는 관광 가이드로 일해요."], "ans": 0, "audio": "Test05_08.mp3"}, {"n": 9, "part": 2, "q": "Who do you think deserves a bonus?", "qko": "누가 보너스를 받을 만하다고 생각하나요?", "opts": ["I think so.", "There are incentives for participation.", "Every salesperson has done well so far."], "optko": ["그런 것 같아요.", "참가에 대한 장려금이 있어요.", "지금까지 모든 판매원들이 잘 했어요."], "ans": 2, "audio": "Test05_09.mp3"}, {"n": 10, "part": 2, "q": "How long has Kendrick been able to speak French?", "qko": "Kendrick이 프랑스어를 구사한 지 얼마나 되었나요?", "opts": ["Is it a language test?", "For nearly a decade.", "We depart for France on June 3."], "optko": ["그것은 언어 시험인가요?", "거의 10년 동안이요.", "저희는 6월 3일에 프랑스로 떠나요."], "ans": 1, "audio": "Test05_10.mp3"}, {"n": 11, "part": 2, "q": "Why didn't someone come to fix the sewing machine?", "qko": "왜 누군가 재봉틀을 수리하러 오지 않았나요?", "opts": ["Right, a warranty.", "I've already taken care of that.", "I don't know anyone either."], "optko": ["맞아요, 보증서요.", "제가 이미 그것을 처리했어요.", "저도 아무도 몰라요."], "ans": 1, "audio": "Test05_11.mp3"}, {"n": 12, "part": 2, "q": "Do guests who visit the hotel pool have to pay an entrance fee?", "qko": "호텔 수영장을 방문하는 고객들이 입장료를 내야 하나요?", "opts": ["I'm not sure.", "Yes, they came through the front entrance.", "Swimming classes are held on Sundays."], "optko": ["잘 모르겠어요.", "네, 그들은 정문 출입구를 통해서 왔어요.", "수영 수업은 일요일마다 열려요."], "ans": 0, "audio": "Test05_12.mp3"}, {"n": 13, "part": 2, "q": "Which of our factories in Asia do you plan to visit?", "qko": "아시아에 있는 우리의 공장들 중 어느 것을 방문할 계획인가요?", "opts": ["I'm delighted to see so many visitors.", "From Tuesday to Friday.", "Only the plants in Taiwan."], "optko": ["이렇게 많은 방문객들을 보게 되어 기뻐요.", "화요일부터 금요일까지요.", "대만에 있는 공장들만요."], "ans": 2, "audio": "Test05_13.mp3"}, {"n": 14, "part": 2, "q": "Do you want to catch a taxi or a bus to the expo center?", "qko": "엑스포 센터까지 택시를 타고 싶은가요, 아니면 버스를 타고 싶은가요?", "opts": ["I'd rather just walk.", "Yes, it's in the city center.", "I'll try renting a booth."], "optko": ["차라리 걷는 게 좋겠어요.", "네, 그것은 시내에 있어요.", "부스를 대여하도록 해볼게요."], "ans": 0, "audio": "Test05_14.mp3"}, {"n": 15, "part": 2, "q": "Where did you purchase the armchairs in the waiting room?", "qko": "대기실에 있는 안락의자를 어디에서 구매했나요?", "opts": ["No, it was inexpensive.", "For a few minutes.", "At the Furniture Finds outlet."], "optko": ["아니요, 그것은 비싸지 않았어요.", "몇 분 동안이요.", "Furniture Finds 매장에서요."], "ans": 2, "audio": "Test05_15.mp3"}, {"n": 16, "part": 2, "q": "Crisp Mart's apples are imported from Mexico.", "qko": "Crisp 시장의 사과들은 멕시코에서 수입돼요.", "opts": ["They're very important people.", "Where exactly are they grown?", "It produces 100 units per hour."], "optko": ["그들은 매우 중요한 사람들이에요.", "정확히 어디에서 그것들이 재배되나요?", "그것은 한 시간당 100개를 생산해요."], "ans": 1, "audio": "Test05_16.mp3"}, {"n": 17, "part": 2, "q": "A membership at the public library is free, right?", "qko": "공립 도서관 회원권은 무료죠, 그렇죠?", "opts": ["No, I don't remember her.", "At a book signing event.", "If you live in town."], "optko": ["아니요, 저는 그녀를 기억하지 못해요.", "도서 사인회 행사에서요.", "당신이 이 동네에 산다면요."], "ans": 2, "audio": "Test05_17.mp3"}, {"n": 18, "part": 2, "q": "When did you become an accountant?", "qko": "당신은 언제 회계사가 되었나요?", "opts": ["By using a calculator.", "A little over two years ago.", "They're coming to our headquarters."], "optko": ["계산기를 이용해서요.", "2년 남짓 전이에요.", "그들은 우리의 본사로 올 거예요."], "ans": 1, "audio": "Test05_18.mp3"}, {"n": 19, "part": 2, "q": "Where can I find a gas station?", "qko": "주유소는 어디에서 찾을 수 있나요?", "opts": ["There are several on Clay Street.", "About $35.", "They were charged a parking fine."], "optko": ["Clay가에 몇 개가 있어요.", "약 35달러예요.", "그들에게 주차 위반 벌금이 부과되었어요."], "ans": 0, "audio": "Test05_19.mp3"}, {"n": 20, "part": 2, "q": "How are you going to spend your time in Jamaica?", "qko": "당신은 자메이카에서 어떻게 시간을 보낼 것인가요?", "opts": ["I want to relax on the beach.", "For over a week.", "Enjoy your vacation."], "optko": ["저는 해변에서 휴식을 취하고 싶어요.", "일주일이 넘는 동안이요.", "즐거운 휴가 보내세요."], "ans": 0, "audio": "Test05_20.mp3"}, {"n": 21, "part": 2, "q": "Which bicycle store do you want to call?", "qko": "당신은 어느 자전거 가게에 전화를 하고 싶나요?", "opts": ["Whichever museum they want to go to.", "I know of a great trail.", "The one by my house."], "optko": ["어느 박물관이든 그들이 가고 싶어 하는 곳이요.", "제가 멋진 길을 알고 있어요.", "제 집 근처에 있는 곳이요."], "ans": 2, "audio": "Test05_21.mp3"}, {"n": 22, "part": 2, "q": "Have you adjusted the shop's design plans to include a storage closet?", "qko": "수납장을 포함하도록 상점의 디자인 도면을 조정했나요?", "opts": ["Here's the item you asked for.", "Mr. Finch designed our Web site.", "I'm working on them."], "optko": ["당신이 찾으신 물건이 여기 있어요.", "Mr. Finch가 우리 웹사이트를 디자인했어요.", "제가 작업하는 중이에요."], "ans": 2, "audio": "Test05_22.mp3"}, {"n": 23, "part": 2, "q": "Would you like me to order dinner if we have to work late?", "qko": "우리가 늦게까지 일해야 한다면, 제가 저녁 식사를 주문할까요?", "opts": ["Yes, thank you.", "I like the roses as well.", "Is this table reserved?"], "optko": ["네, 고마워요.", "저도 그 장미를 좋아해요.", "이 자리는 예약되었나요?"], "ans": 0, "audio": "Test05_23.mp3"}, {"n": 24, "part": 2, "q": "Why hasn't Nicholas completed his review for the paper?", "qko": "Nicholas는 왜 서류 검토를 끝마치지 않았나요?", "opts": ["He has more urgent tasks to take care of.", "Our branch sells paper products.", "Your piece is good."], "optko": ["그는 처리해야 할 더 급한 업무가 있어요.", "저희 지점은 종이 제품을 팔아요.", "당신의 기사는 훌륭해요."], "ans": 0, "audio": "Test05_24.mp3"}, {"n": 25, "part": 2, "q": "Do you want to shop for more souvenirs, or can we go now?", "qko": "당신은 더 많은 기념품을 사고 싶나요, 아니면 이제 가도 되나요?", "opts": ["Gifts for some of my colleagues.", "I'm ready to go.", "The shop opened in August."], "optko": ["저의 동료들을 위한 선물이요.", "저는 갈 준비가 됐어요.", "상점은 8월에 문을 열었어요."], "ans": 1, "audio": "Test05_25.mp3"}, {"n": 26, "part": 2, "q": "The blueprint was checked by the architect, wasn't it?", "qko": "청사진을 건축가에게 확인 받았죠, 안 그런가요?", "opts": ["It looks more red to me.", "Check the rules first.", "He'll go over it this afternoon."], "optko": ["저에게는 좀 더 빨간색으로 보여요.", "규칙을 먼저 확인하세요.", "그는 오늘 오후에 검토할 거예요."], "ans": 2, "audio": "Test05_26.mp3"}, {"n": 27, "part": 2, "q": "The water park is offering a seasonal promotion.", "qko": "워터파크에서 계절 할인을 제공하고 있어요.", "opts": ["What is it, exactly?", "While standing in line.", "Be sure to bring him a raincoat."], "optko": ["그게 정확히 무엇인가요?", "줄을 서 있는 동안이요.", "그에게 우비를 가져다 주세요."], "ans": 0, "audio": "Test05_27.mp3"}, {"n": 28, "part": 2, "q": "Who wrote the initial presentation for the microwave marketing campaign?", "qko": "누가 전자레인지 광고 캠페인의 첫 발표를 작성했나요?", "opts": ["I can find out for you.", "For our target market.", "Alan did most of the hiring."], "optko": ["제가 확인해드릴 수 있어요.", "우리의 목표 시장을 위해서요.", "Alan이 채용 대부분을 진행했어요."], "ans": 0, "audio": "Test05_28.mp3"}, {"n": 29, "part": 2, "q": "Isn't it time to head to the book signing?", "qko": "책 사인회 행사에 갈 시간 아닌가요?", "opts": ["You're ahead in the competition.", "Actually, it starts after lunch.", "Yes, I attended it."], "optko": ["당신은 경기에서 앞서고 있어요.", "사실, 그것은 점심 후에 시작해요.", "네, 저는 거기에 참석했었어요."], "ans": 1, "audio": "Test05_29.mp3"}, {"n": 30, "part": 2, "q": "Would you mind stopping by my desk in a bit?", "qko": "잠시 후에 제 자리에 들러주시겠어요?", "opts": ["I've stopped buying those.", "Because none are mine.", "I think I'll be able to do that."], "optko": ["저는 그것들을 사는 것을 그만두었어요.", "아무 것도 제 것이 아니기 때문이에요.", "그렇게 할 수 있을 것 같아요."], "ans": 2, "audio": "Test05_30.mp3"}, {"n": 31, "part": 2, "q": "The container in the refrigerator belongs to me.", "qko": "냉장고에 있는 용기는 제 것이에요.", "opts": ["Did you mark it with your name?", "While I was cleaning it out.", "Ms. Valero owns the land."], "optko": ["그것에 당신의 이름을 표시했나요?", "제가 그것을 청소하는 동안에요.", "Ms. Valero가 그 땅을 소유하고 있어요."], "ans": 0, "audio": "Test05_31.mp3"}], "sets34": [{"start": 32, "part": 3, "intro": "", "graphic": false, "speakers": "M-Ca / W-Am", "audio": "Test05_32-34.mp3", "qs": [{"n": 32, "q": "What problem does the man mention?", "opts": ["A password is incorrect.", "A business has been closed.", "A screen is malfunctioning.", "A receipt was lost."], "ans": 2, "ko": "남자는 어떤 문제를 언급하는가?"}, {"n": 33, "q": "What does the woman recommend doing?", "opts": ["Trying another device", "Pressing a button", "Calling a technician", "Waiting in line"], "ans": 0, "ko": "여자는 무엇을 하라고 제안하는가?"}, {"n": 34, "q": "What does the woman offer the man?", "opts": ["A flyer", "A voucher", "A calendar", "An invitation card"], "ans": 2, "ko": "여자는 남자에게 무엇을 제공하는가?"}], "script": [{"sp": "M", "en": "Pardon me . . . Could you help me, please? I was trying to use one of your bank's cash machines, but the touch screen isn't responding.", "ko": "실례합니다… 저를 도와줄 수 있으신가요? 귀사의 은행 현금 인출기 중 하나를 이용하려고 했는데, 터치스크린이 반응하지 않아요."}, {"sp": "W", "en": "I'm sorry. That error has been coming up repeatedly this morning. A repairperson should be on the way. Meanwhile, I recommend using the machine near the exit instead.", "ko": "죄송합니다. 그 오류는 오늘 아침에 반복적으로 발생하고 있습니다. 수리공이 오고 있는 중이에요. 그동안, 출구 가까이에 있는 기계를 대신 이용하는 것을 권해드립니다."}, {"sp": "M", "en": "Ah . . . I also tried that one, and it's not working either. I'm in a rush, so I'll consult one of the tellers.", "ko": "아… 그것도 써봤는데, 작동하지 않아요. 제가 서둘러야 해서 창구 직원 중 한 분과 상담할게요."}, {"sp": "W", "en": "Of course. And to apologize for the inconvenience, here's a free desk calendar.", "ko": "물론이죠. 그리고 불편에 대해 사과드리기 위해 여기 무료 탁상용 달력을 드리겠습니다."}]}, {"start": 35, "part": 3, "intro": "", "graphic": false, "speakers": "W-Br / M-Au", "audio": "Test05_35-37.mp3", "qs": [{"n": 35, "q": "What does the man say about PointAlert products?", "opts": ["They are very expensive.", "They are out of stock.", "They are advertised online.", "They are being discounted."], "ans": 1, "ko": "남자는 PointAlert 제품에 관해 무엇을 말하는가?"}, {"n": 36, "q": "What changed last month?", "opts": ["An application requirement", "A sales promotion", "A membership program", "A business location"], "ans": 3, "ko": "지난달에 무엇이 바뀌었는가?"}, {"n": 37, "q": "What will the woman most likely do next?", "opts": ["Make a purchase", "Replace a battery", "Download a program", "Call a branch"], "ans": 2, "ko": "여자는 다음에 무엇을 할 것 같은가?"}], "script": [{"sp": "W", "en": "Hello. I oversee an apartment complex, and I'm interested in installing the home security cameras you sell. Do you carry the brand . . . ah . . . PointAlert?", "ko": "안녕하세요. 저는 아파트 단지를 감독하는데, 당신이 판매하는 주택 무인 카메라를 설치하는 데 관심이 있어요. 아... PointAlert라는 브랜드를 취급하시나요?"}, {"sp": "M", "en": "Unfortunately, those products all sold out last week. We sell similar items, though, if you'd like to come by and check them out.", "ko": "안타깝게도, 그 제품들은 지난주에 모두 다 팔렸습니다. 하지만 잠깐 들러서 확인하고 싶으시다면 저희는 비슷한 물품들도 판매합니다."}, {"sp": "W", "en": "OK. Your chain has an outlet on Marigold Street, right?", "ko": "알겠습니다. 당신의 체인점은 Marigold가에 매장이 있죠, 그렇죠?"}, {"sp": "M", "en": "Actually, that branch moved to a different area last month. If you download our free smartphone application, you can see the locations of all our current retail shops.", "ko": "사실, 그 지점은 지난달에 다른 지역으로 옮겼습니다. 저희의 무료 스마트폰 애플리케이션을 다운로드하시면, 현재 모든 소매점들의 위치를 보실 수 있습니다."}, {"sp": "W", "en": "Thanks. I'll do that now.", "ko": "고맙습니다. 지금 그것을 할게요."}]}, {"start": 38, "part": 3, "intro": "", "graphic": false, "speakers": "W-Am / M-Au", "audio": "Test05_38-40.mp3", "qs": [{"n": 38, "q": "Why does the woman ask the man for help?", "opts": ["She cannot access a system.", "She cannot attend an event.", "She's worried about a deadline.", "She's unfamiliar with a process."], "ans": 3, "ko": "여자는 왜 남자에게 도움을 청하는가?"}, {"n": 39, "q": "What did the woman do last week?", "opts": ["Visited a client", "Attended a conference", "Took a vacation", "Completed a project"], "ans": 1, "ko": "여자는 지난주에 무엇을 했는가?"}, {"n": 40, "q": "In which department does Ms. Rivera most likely work?", "opts": ["Information technology", "Human resources", "Accounting", "Marketing"], "ans": 2, "ko": "Ms. Rivera는 어떤 부서에서 일하는 것 같은가?"}], "script": [{"sp": "W", "en": "Lance, I went on a business trip last week. But I've never had to turn in an expense report before. Could you help me out?", "ko": "Lance, 저는 지난주에 출장을 다녀왔어요. 하지만 이전에 경비 보고서를 제출해본 적이 없어서요. 저를 좀 도와주시겠어요?"}, {"sp": "M", "en": "Sure. Were you at the human resources conference in San Francisco?", "ko": "물론이죠. 샌프란시스코에서 열린 인적 자원 학회에 있었나요?"}, {"sp": "W", "en": "Yeah, I was there. Our boss told me to keep my meal and taxi receipts. How should I submit them to the accounting department?", "ko": "네, 그곳에 있었어요. 저희 상사가 제게 식사와 택시 영수증을 보관하라고 말씀하셨어요. 회계부서에 그것들을 어떻게 제출하면 되나요?"}, {"sp": "M", "en": "I'd suggest entering all the information into the report first. Then, scan each receipt and attach them along with the report to an e-mail. Ah . . . and address it to Ms. Rivera. She handles all business-related expenses.", "ko": "먼저 모든 정보를 보고서에 입력하는 것을 제안해요. 그다음에, 각 영수증을 스캔해서 보고서와 함께 이메일에 첨부하세요. 아... 그리고 그걸 Ms. Rivera에게 보내세요. 그녀가 모든 업무 관련 비용을 처리하거든요."}]}, {"start": 41, "part": 3, "intro": "", "graphic": false, "speakers": "W1-Am / M-Ca / W2-Br", "audio": "Test05_41-43.mp3", "qs": [{"n": 41, "q": "What are the speakers mainly discussing?", "opts": ["Parking options", "Room rates", "Payment methods", "Travel plans"], "ans": 3, "ko": "화자들은 주로 무엇에 관해 이야기하고 있는가?"}, {"n": 42, "q": "What does the man suggest?", "opts": ["Unpacking some bags", "Signing up for an activity", "Doing activities separately", "Posing for a photograph"], "ans": 2, "ko": "남자는 무엇을 제안하는가?"}, {"n": 43, "q": "What will Jen probably do next?", "opts": ["Ask for directions", "Check in to a hotel", "Go to a park", "Provide recommendations"], "ans": 0, "ko": "Jen은 다음에 무엇을 할 것 같은가?"}], "script": [{"sp": "W1", "en": "Marty and Jen, are you ready to leave the guesthouse and do some sightseeing?", "ko": "Marty와 Jen, 게스트 하우스에서 나가 관광을 할 준비가 됐나요?"}, {"sp": "M", "en": "Sure! I'm excited to see the amazing mountain views at the state park nearby.", "ko": "물론이죠! 근처의 주립 공원에서 멋진 산의 경치를 보게 되어 기쁘네요."}, {"sp": "W2", "en": "We're going there today? I thought we'd shop at the outlet mall.", "ko": "우리가 오늘 그곳에 가나요? 저는 쇼핑몰에서 쇼핑을 할 것이라고 생각했어요."}, {"sp": "M", "en": "Well, maybe we can split up. Renee and I want to spend the morning at the park. So, why don't we meet you at the outlet mall for lunch, Jen?", "ko": "음, 아마 우리가 갈라질 수 있을 거예요. Renee와 저는 공원에서 아침을 보내고 싶어요. 그러니, 점심 먹을 때 쇼핑몰에서 우리가 당신을 만나는 게 어때요, Jen?"}, {"sp": "W2", "en": "OK, but I'm not sure where the mall is. Maybe I'll ask the front desk clerk.", "ko": "알았어요, 하지만 저는 쇼핑몰이 어디에 있는지 몰라요. 아마 안내 데스크 직원에게 물어봐야겠어요."}, {"sp": "M", "en": "Good idea. I'm sure she can tell you how to get there.", "ko": "좋은 생각이에요. 그녀가 어떻게 그곳에 가는지 알려줄 수 있을 거예요."}]}, {"start": 44, "part": 3, "intro": "", "graphic": false, "speakers": "M-Au / W-Am", "audio": "Test05_44-46.mp3", "qs": [{"n": 44, "q": "What are the speakers mainly discussing?", "opts": ["Training some employees", "Booking a flight", "Planning an event", "Raising some funds"], "ans": 2, "ko": "화자들은 주로 무엇에 관해 이야기하고 있는가?"}, {"n": 45, "q": "What is a feature of the restaurant?", "opts": ["It is close to the office.", "It serves good food.", "It offers private spaces.", "It has been renovated."], "ans": 2, "ko": "식당의 특징은 무엇인가?"}, {"n": 46, "q": "Why does the woman say, \"We're attending a budget meeting that day\"?", "opts": ["To make a complaint", "To explain a request", "To respond to an inquiry", "To decline an invitation"], "ans": 1, "ko": "여자는 왜 \"저희는 그날 예산 회의에 참석하잖아요\"라고 말하는가?"}], "script": [{"sp": "M", "en": "Hi, Claire. How are the preparations for Maya's birthday party going?", "ko": "안녕하세요, Claire. Maya의 생일 파티 준비는 어떻게 되어가고 있나요?"}, {"sp": "W", "en": "Pretty well. I sent out the invitations yesterday. And how about booking a table at the Korean restaurant she likes?", "ko": "아주 잘 되고 있어요. 저는 어제 초대장을 보냈어요. 그리고 그녀가 좋아하는 한식당에 자리를 예약하는 게 어때요?"}, {"sp": "M", "en": "Sure. I have that place's phone number saved. I'll call right now and see if there are any private rooms available.", "ko": "좋아요. 저는 그곳 전화번호를 저장해놨어요. 지금 전화해서 이용 가능한 개인실이 있는지 알아볼게요."}, {"sp": "W", "en": "Great. And don't forget to make the reservation for 8 P.M. We're attending a budget meeting that day.", "ko": "좋아요. 그리고 오후 8시로 예약하는 것을 잊지 마세요. 저희는 그날 예산 회의에 참석하잖아요."}]}, {"start": 47, "part": 3, "intro": "", "graphic": false, "speakers": "M-Ca / W-Br", "audio": "Test05_47-49.mp3", "qs": [{"n": 47, "q": "What will the man's company do?", "opts": ["Launch a product", "Open a branch", "Cancel an order", "Support a competition"], "ans": 3, "ko": "남자의 회사는 무엇을 할 것인가?"}, {"n": 48, "q": "What does the woman offer to do?", "opts": ["Speed up a process", "Check a system", "Provide a refund", "Show a sample"], "ans": 0, "ko": "여자는 무엇을 해주겠다고 제안하는가?"}, {"n": 49, "q": "What will most likely happen next?", "opts": ["A package will be delivered.", "A payment will be made.", "A service will be canceled.", "An image will be sent."], "ans": 3, "ko": "다음에 무슨 일이 일어날 것 같은가?"}], "script": [{"sp": "M", "en": "Hi. I'd like to place an order for 50 printed T-shirts for a race my company will sponsor.", "ko": "안녕하세요. 저희 회사에서 후원할 경주를 위해 50벌의 프린트 티셔츠를 주문하고 싶습니다."}, {"sp": "W", "en": "OK. Have you ordered with us before?", "ko": "네. 이전에 저희에게 주문하신 적이 있으신가요?"}, {"sp": "M", "en": "Oh, yes. Our corporate account number is 48827.", "ko": "아, 네. 저희 회사의 계정 번호는 48827입니다."}, {"sp": "W", "en": "Great. And when do you need the items delivered by?", "ko": "좋습니다. 그럼 언제까지 물품을 배달받아셔야 하나요?"}, {"sp": "M", "en": "May 10, if possible. The event is being held on May 15.", "ko": "가능하다면, 5월 10일이요. 행사는 5월 15일에 열립니다."}, {"sp": "W", "en": "Hmm . . . To meet that date, we can provide an expedited service. But there will be an additional charge of $20, which brings the total amount to $170. Is that all right?", "ko": "흠... 날짜를 맞추기 위해 저희가 긴급 서비스를 제공할 수 있습니다. 하지만 20달러의 추가 비용이 있을 것이고, 이로 인해 총액은 170달러가 됩니다. 괜찮으신가요?"}, {"sp": "M", "en": "Yes, that's fine. I'll e-mail you the design now.", "ko": "네, 괜찮습니다. 제가 지금 디자인을 이메일로 보내드리겠습니다."}]}, {"start": 50, "part": 3, "intro": "", "graphic": false, "speakers": "M-Au / W-Br", "audio": "Test05_50-52.mp3", "qs": [{"n": 50, "q": "What type of business does the man most likely work for?", "opts": ["A fitness center", "A staffing agency", "A moving company", "An advertising firm"], "ans": 0, "ko": "남자는 어떤 종류의 업체에서 일하는 것 같은가?"}, {"n": 51, "q": "What does the man say about the gym?", "opts": ["It will host an event.", "It has been inspected.", "It will reopen soon.", "It has some new machines."], "ans": 3, "ko": "남자는 체육관에 관해 무엇이라고 말하는가?"}, {"n": 52, "q": "What will the man probably do next?", "opts": ["Make some inquiries", "Complete some paperwork", "Demonstrate a product", "Distribute a pamphlet"], "ans": 0, "ko": "남자는 다음에 무엇을 할 것 같은가?"}], "script": [{"sp": "M", "en": "Before we start the interview, I want to point out that the personal trainer position needs to be filled for one month only.", "ko": "저희가 면접을 시작하기 전에, 개인 트레이너 자리는 단 한 달 동안임을 언급하고 싶습니다."}, {"sp": "W", "en": "Yes, I saw that in the job advertisement. I'm going to move overseas in six weeks, so I need a short-term job.", "ko": "네, 구인 광고에서 봤어요. 저는 6주 후에 해외로 이사할 거라서 단기적인 직업이 필요해요."}, {"sp": "M", "en": "Good. Our gym will be very busy in January. And the new employee will assist our director, Antoine Hart, during that time.", "ko": "좋아요. 저희 체육관은 1월에 매우 바쁠 거예요. 그리고 새로운 직원은 그 기간 동안 저희 관리자인 Antoine Hart를 도울 거예요."}, {"sp": "W", "en": "Are you expecting more customers because it's the new year?", "ko": "새해이기 때문에 더 많은 고객들이 올 거라고 예상하시나요?"}, {"sp": "M", "en": "Partly, but also because we're running a big promotion since we replaced some of our workout machines last month . . . Anyway, now I'll ask you some questions about your past work experience.", "ko": "어느 정도는 그런데, 지난달에 일부 운동 기구들을 교체한 이후로 큰 판촉 행사를 진행하고 있기 때문이기도 해요… 그건 그렇고, 이제 당신의 이전 경력에 대해 몇 가지 질문을 드릴게요."}]}, {"start": 53, "part": 3, "intro": "", "graphic": false, "speakers": "W-Am / M-Cn", "audio": "Test05_53-55.mp3", "qs": [{"n": 53, "q": "What are the speakers mainly discussing?", "opts": ["Automated devices", "A Web site's design", "Training workshops", "A customer review"], "ans": 0, "ko": "화자들은 주로 무엇에 관해 이야기하고 있는가?"}, {"n": 54, "q": "What does the woman expect to happen?", "opts": ["Customers will complain.", "Staff will be replaced.", "Revenue will increase.", "Installations will be delayed."], "ans": 2, "ko": "여자는 무엇이 일어날 것이라고 예상하는가?"}, {"n": 55, "q": "What did the woman do an hour ago?", "opts": ["Paid a delivery person", "Contacted a worker", "Checked a text message", "Conducted an interview"], "ans": 1, "ko": "여자는 한 시간 전에 무엇을 했는가?"}], "script": [{"sp": "W", "en": "Guess what, Andrei? Our pizza shop ordered some self-service kiosks.", "ko": "있잖아요, Andrei? 우리 피자 가게가 셀프서비스 주문 기계들을 주문했어요."}, {"sp": "M", "en": "Ah . . . Are they able to send text message notifications about orders to customers' phones?", "ko": "아... 그것들은 고객들의 휴대 전화로 주문에 대한 문자 메시지 알림을 보낼 수 있나요?"}, {"sp": "W", "en": "That's right. I expect they'll help us boost sales as many people find them very convenient.", "ko": "맞아요. 많은 사람들이 그것들을 매우 편리하다고 생각하니 저는 그것들이 매출을 증가시키는 데 도움이 될 것이라고 예상해요."}, {"sp": "M", "en": "Hmm . . . I'm not so sure. I know many customers who prefer dealing directly with staff here.", "ko": "흠... 저는 잘 모르겠어요. 저는 이곳의 직원들을 직접 상대하는 것을 선호하는 많은 고객들을 알고 있어요."}, {"sp": "W", "en": "Well, let's see how patrons respond on the first day the machines are available. An hour ago, I called the technician who will install them, and he said they'll be ready this Friday.", "ko": "음, 기계를 이용할 수 있는 첫날에 고객들이 어떻게 반응하는지를 보도록 해요. 한 시간 전에 제가 그것들을 설치해 줄 기술자에게 전화했는데, 이번 주 금요일에 그것들이 준비될 거라고 그가 말했어요."}]}, {"start": 56, "part": 3, "intro": "", "graphic": false, "speakers": "W-Br / M-Au", "audio": "Test05_56-58.mp3", "qs": [{"n": 56, "q": "Who is Brenda Frost?", "opts": ["A hair stylist", "A personal assistant", "An accountant", "A property owner"], "ans": 3, "ko": "Brenda Frost는 누구인가?"}, {"n": 57, "q": "Why does the woman say, \"We've established a large client base in the neighborhood\"?", "opts": ["To confirm that a decision was reached", "To explain why she agrees with an opinion", "To show how she achieved a goal", "To indicate that a plan is unacceptable"], "ans": 1, "ko": "여자는 왜 \"우리는 인근에서 다수의 고객층을 확립했잖아요\"라고 말하는가?"}, {"n": 58, "q": "What does the woman say she will do this afternoon?", "opts": ["Make a phone call", "Address a complaint", "Change a work schedule", "Adjust a budget"], "ans": 0, "ko": "여자는 오늘 오후에 무엇을 할 것이라고 말하는가?"}], "script": [{"sp": "W", "en": "The lease for our salon is almost over, Francis. And, according to our landlord, Brenda Frost, our monthly rent will be increased by $300 per month next year.", "ko": "우리 상점의 임대차 계약이 거의 끝났어요, Francis. 그리고 건물주 Brenda Frost에 따르면, 내년에 우리 월세가 한 달에 300달러가 오를 거래요."}, {"sp": "M", "en": "Wow! That's a big change. But I don't think it would be wise to try to relocate.", "ko": "우와! 그것은 큰 변화네요. 하지만 저는 이전을 시도하는 게 현명한 것 같지 않아요."}, {"sp": "W", "en": "Not at all. We've established a large client base in the neighborhood. But I'm not sure if we can afford the new rental rate.", "ko": "전혀 아니죠. 우리는 인근에서 다수의 고객층을 확립했잖아요. 하지만 우리가 새로운 임대료를 낼 수 있을지 모르겠어요."}, {"sp": "M", "en": "I think we can manage it. Our budget looks OK for this year.", "ko": "저는 우리가 감당할 수 있을 거라고 생각해요. 올해 우리 예산이 괜찮아 보이거든요."}, {"sp": "W", "en": "You're right. I'll call Ms. Frost this afternoon to tell her about our decision to stay here.", "ko": "당신 말이 맞아요. 제가 오늘 오후에 Ms. Frost에게 전화해서 여기에 계속 있겠다는 우리의 결정을 알려줄게요."}]}, {"start": 59, "part": 3, "intro": "", "graphic": false, "speakers": "W-Br / M-Au", "audio": "Test05_59-61.mp3", "qs": [{"n": 59, "q": "What is the man's area of expertise?", "opts": ["Real estate", "Advertising", "Radio broadcasting", "Finance"], "ans": 3, "ko": "남자의 전문 분야는 무엇인가?"}, {"n": 60, "q": "What does the woman ask the man to do?", "opts": ["Interview a guest", "Share some advice", "Announce some commercials", "Sign a contract"], "ans": 1, "ko": "여자는 남자에게 무엇을 하라고 요청하는가?"}, {"n": 61, "q": "What will most likely happen next?", "opts": ["The next show will be introduced.", "A traffic report will be broadcast.", "Some calls will be taken.", "A prize will be given away."], "ans": 2, "ko": "다음에 무슨 일이 일어날 것 같은가?"}], "script": [{"sp": "W", "en": "This is Candace Keller on WGN Top Radio in Austin. As advertised, I will now interview Jason Carter, a successful financial consultant and host of the new TV show Deal Me In. So, Jason, can you tell us about this new show?", "ko": "오스틴에서 WGN Top 라디오의 Candace Keller입니다. 광고된 것처럼, 저는 이제 성공한 재정 자문 위원이자 새로운 TV 쇼 Deal Me In의 진행자인 Jason Carter를 인터뷰할 것입니다. 자, Jason, 이 새로운 쇼에 대해 저희에게 알려주실 수 있나요?"}, {"sp": "M", "en": "Certainly. The program is filmed like a talk show and focuses on people's financial concerns, like their investments.", "ko": "물론이죠. 그 프로그램은 토크 쇼처럼 촬영되며 투자와 같은 사람들의 재무 관심사에 초점을 맞춥니다."}, {"sp": "W", "en": "Sounds interesting. And what tips can you give our listeners now about managing their money?", "ko": "흥미롭게 들리네요. 그리고 지금 저희 청취자들에게 그들의 재산을 관리하는 것에 대해 어떤 조언을 해주실 수 있나요?"}, {"sp": "M", "en": "The most important thing is to keep track of one's spending.", "ko": "가장 중요한 것은 자신의 지출에 대해 계속 파악하고 있는 것입니다."}, {"sp": "W", "en": "I see. Well, let's listen to some phone calls now from the people out there who've tuned in to this radio show.", "ko": "알겠습니다. 음, 이제 이 라디오 쇼를 청취하고 계신 분들로부터 온 전화를 들어보죠."}]}, {"start": 62, "part": 3, "intro": "", "graphic": true, "speakers": "W-Am / M-Cn", "audio": "Test05_62-64.mp3", "qs": [{"n": 62, "q": "What did the woman recently do?", "opts": ["Renewed a bus pass", "Relocated to a new area", "Published a travel book", "Made a career change"], "ans": 1, "ko": "여자는 최근에 무엇을 했는가?"}, {"n": 63, "q": "Look at the graphic. Which bus will the woman most likely take?", "opts": ["180", "195", "199", "210"], "ans": 1, "ko": "시각 자료를 보시오. 여자는 어떤 버스를 탈 것 같은가?"}, {"n": 64, "q": "What does the woman ask the man about?", "opts": ["Why a business is closed", "When a schedule was updated", "If he has change for a bill", "Whether she will be on time"], "ans": 3, "ko": "여자는 남자에게 무엇에 관해 문의하는가?"}], "script": [{"sp": "W", "en": "Excuse me. I've just recently moved to this city, and I don't know my way around well. Could you tell me which bus travels to Windsor Station?", "ko": "실례합니다. 저는 최근에 이 도시로 이사를 왔는데, 지리를 잘 몰라서요. 어떤 버스가 Windsor역으로 가는지 알려주실 수 있나요?"}, {"sp": "M", "en": "Hmm . . . You have a few options. But the quickest is the express bus.", "ko": "흠... 몇 가지 선택 사항들이 있어요. 하지만 가장 빠른 것은 급행 버스예요."}, {"sp": "W", "en": "Thanks, I'll take that one! And, um . . . Do you think I'll be able to get to where I'm going by noon? I'm running late for a dental appointment.", "ko": "고마워요, 그것을 탈게요! 그리고 음... 제가 가는 곳에 정오까지 도착할 수 있을까요? 치과 진료 예약에 늦을 거 같아서요."}, {"sp": "M", "en": "Oh, certainly. The bus arrives every five minutes, and you'll only be traveling 10 blocks or so.", "ko": "아, 물론이죠. 버스는 5분마다 오고, 10블록 정도만 가시면 돼요."}], "gimg": "hk_t5_g62.jpg"}, {"start": 65, "part": 3, "intro": "", "graphic": true, "speakers": "W-Am, M-Au", "audio": "Test05_65-67.mp3", "qs": [{"n": 65, "q": "Who most likely is the woman?", "opts": ["A repairperson", "A graphic designer", "A gallery owner", "A sales representative"], "ans": 1, "ko": "여자는 누구인 것 같은가? (A) 수리공 (B) 그래픽 디자이너 (C) 미술관 소유주 (D) 영업 사원"}, {"n": 66, "q": "Look at the graphic. Which section should the man refer to?", "opts": ["Installation", "Tools", "Techniques", "Exporting"], "ans": 2, "ko": "시각 자료를 보시오. 남자는 어떤 부분을 참조해야 하는가? (A) 설치 (B) 도구 (C) 기술 (D) 내보내기"}, {"n": 67, "q": "Why does the woman suggest reviewing some content?", "opts": ["To find an image", "To prepare for a test", "To resolve a complaint", "To improve a presentation"], "ans": 1, "ko": "여자는 왜 내용을 복습하는 것을 제안하는가? (A) 이미지를 찾기 위해 (B) 시험을 준비하기 위해 (C) 불평을 해결하기 위해 (D) 발표를 개선하기 위해"}], "script": [{"sp": "W", "en": "Thanks for attending the second session of our training workshop for Styx Photo Editing software. Before I start, does anyone have questions about yesterday's session?", "ko": "Styx 사진 편집 소프트웨어에 대한 저희 교육 워크숍의 두 번째 수업에 참석해주셔서 감사합니다. 시작하기 전에, 어제 수업에 대해 질문 있으신 분 계신가요?"}, {"sp": "M", "en": "Yeah, I do. Can you show us how to switch color ranges again, please?", "ko": "네, 있어요. 색상 범위를 바꾸는 방법을 다시 보여주시겠어요?"}, {"sp": "W", "en": "Sure, I'll show you in a few minutes. And in the future, you can find that information in the user manual.", "ko": "네, 제가 잠시 후에 보여드릴게요. 그리고 추후에는 사용자 매뉴얼에서 그 정보를 찾으실 수 있어요."}, {"sp": "M", "en": "Yes, I glanced through it. But I couldn't find anything in the Tools section about color ranges.", "ko": "네, 저는 그것을 쭉 훑어보았어요. 하지만 저는 색상 범위에 대해 도구 부분에서 아무것도 찾지 못했어요."}, {"sp": "W", "en": "Oh, it's not in that section. It's actually on page 7. So you should check there. At any rate, you should review all the content to get ready for our exam tomorrow.", "ko": "아, 그것은 그 부분에 있지 않아요. 그것은 사실 7쪽에 있어요. 그러니까 그곳을 확인해 보세요. 어쨌든, 내일 우리 시험에 대비하여 모든 내용을 복습하셔야 해요."}], "gimg": "hk_t5_g65.jpg"}, {"start": 68, "part": 3, "intro": "", "graphic": true, "speakers": "W-Br, M-Ca", "audio": "Test05_68-70.mp3", "qs": [{"n": 68, "q": "What does the man say he will do this week?", "opts": ["Hand in a report", "Achieve a sales target", "Attend a gathering", "Purchase a new phone"], "ans": 0, "ko": "남자는 이번 주에 무엇을 할 것이라고 말하는가? (A) 보고서를 제출한다. (B) 판매 목표를 달성한다. (C) 모임에 참석한다. (D) 새로운 전화기를 구입한다."}, {"n": 69, "q": "Look at the graphic. Which category was the woman surprised about?", "opts": ["Quality of calls", "Monthly rates", "Choice of calling plans", "Customer service"], "ans": 3, "ko": "시각 자료를 보시오. 여자는 어떤 항목에 놀랐는가? (A) 통화 품질 (B) 월별 요금 (C) 요금제 선택권 (D) 고객 서비스"}, {"n": 70, "q": "What does the woman say about Warren Jordan?", "opts": ["He received a license recently.", "He provided some assistance previously.", "He plans to hire some new staff.", "He is concerned about a contract."], "ans": 1, "ko": "여자는 Warren Jordan에 관해 무엇을 말하는가? (A) 그는 최근에 면허를 받았다. (B) 그는 이전에 도움을 주었다. (C) 그는 새로운 직원을 고용할 계획이다. (D) 그는 계약에 대해 걱정한다."}], "script": [{"sp": "W", "en": "How's the analysis of our customer survey going, Casey?", "ko": "우리 고객 설문 조사에 대한 분석이 어떻게 되어가고 있나요, Casey?"}, {"sp": "M", "en": "I just need to type up the report . . . I'll submit it by the end of this week. But would you like to look at what I've got so far?", "ko": "저는 이제 보고서를 입력하기만 하면 돼요… 제가 그것을 이번 주 후반까지 제출할게요. 하지만 제가 지금까지 끝낸 부분을 보시겠어요?"}, {"sp": "W", "en": "Sure. Hmm . . . I can understand why most customers rated our choice of calling plans as very poor. However, I'm surprised to see another category is poorly rated.", "ko": "네. 흠… 저는 왜 대부분의 고객들이 저희 요금제 선택권을 매우 좋지 않다고 평가했는지 알 것 같아요. 하지만, 저는 다른 항목도 좋지 않게 평가된 것을 보니 놀랍네요."}, {"sp": "M", "en": "I wasn't expecting that either. What do you think we should do to address this issue?", "ko": "저도 그건 예상하지 못했어요. 우리가 이 문제를 처리하기 위해 무엇을 해야 할까요?"}, {"sp": "W", "en": "I propose hiring an expert in this area to consult with us. Warren Jordan at Handler Consulting Agency might be a good choice since he helped us improve our call center.", "ko": "저는 저희와 함께 상의할 이 분야의 전문가를 한 분 고용하는 것을 제안해요. Handler 컨설팅 회사의 Warren Jordan이 우리 콜센터가 나아지는 데 도움을 주었었기 때문에 그가 좋은 선택이 될 것 같아요."}], "gimg": "hk_t5_g68.jpg"}, {"start": 71, "part": 4, "intro": "", "graphic": false, "speakers": "M-Ca", "audio": "Test05_71-73.mp3", "qs": [{"n": 71, "q": "What type of business does the speaker work for?", "opts": ["A delivery service", "A printing company", "An office supply store", "A paper manufacturer"], "ans": 2, "ko": "화자는 어떤 종류의 업체에서 일하는가? (A) 택배 회사 (B) 인쇄소 (C) 사무용품점 (D) 용지 제조사"}, {"n": 72, "q": "What problem does the speaker mention?", "opts": ["A warehouse is understaffed.", "A vendor is no longer in business.", "Some color options have changed.", "Some shipments have been delayed."], "ans": 1, "ko": "화자는 어떤 문제를 언급하는가? (A) 창고에 인원이 부족하다. (B) 판매 회사가 더 이상 영업을 하지 않는다. (C) 색상 선택권이 변경되었다. (D) 배송품들이 지연되었다."}, {"n": 73, "q": "Why is the listener asked to return the call?", "opts": ["To discuss available products", "To confirm an e-mail address", "To provide payment details", "To review a return policy"], "ans": 0, "ko": "청자는 왜 다시 전화를 하도록 요청받는가? (A) 이용 가능한 제품들을 논의하기 위해 (B) 이메일 주소를 확인하기 위해 (C) 지불 정보를 제공하기 위해 (D) 환불 정책을 검토하기 위해"}], "script": [{"sp": "M", "en": "Hello, Ms. Vincent. This is Howard Rogan from Division Center Supplies. I'm calling about the white printer paper you ordered for your office. Well, there's a problem. The manufacturer of the product you selected—Wellington Paper Products—just went out of business. You paid for 50 boxes, but we only have 20 in our warehouse. However, we do carry other paper products of a similar quality, which we can send instead. But first, I'd like to review your choices with you. Call me back at your earliest convenience, and I'll be happy to go over the options.", "ko": "안녕하세요, Ms. Vincent. 저는 Division Center Supplies사의 Howard Rogan입니다. 저는 귀하가 귀하의 사무실을 위해 주문하신 흰색 프린터 용지에 관해 전화드립니다. 음, 문제가 하나 있습니다. 귀하께서 선택하신 제품의 제조사인 Wellington Paper Products사가 막 폐업했습니다. 귀하께서 50개의 상자에 대한 요금을 지불하셨지만, 저희 창고에는 20개만 있습니다. 하지만 저희는 유사한 품질의 다른 용지 제품들을 취급하고 있으며, 그것들을 대신 보내드릴 수 있습니다. 하지만 먼저, 저는 함께 귀하의 선택을 검토하고 싶습니다. 가급적 빨리 저에게 다시 전화해주시면, 저는 기꺼이 선택 사항들을 검토하겠습니다."}]}, {"start": 74, "part": 4, "intro": "", "graphic": false, "speakers": "Br", "audio": "Test05_74-76.mp3", "qs": [{"n": 74, "q": "Why does the speaker say, \"So it wasn't safe to walk around\"?", "opts": ["To make a complaint", "To justify a detour", "To request a repair", "To explain a delay"], "ans": 3, "ko": "화자는 왜 \"그래서 돌아다니기에 안전하지 않았습니다\"라고 말하는가? (A) 항의를 하기 위해 (B) 우회를 해명하기 위해 (C) 수리를 요청하기 위해 (D) 지연의 이유를 설명하기 위해"}, {"n": 75, "q": "What will happen next week?", "opts": ["A construction project will be completed.", "Some community classes will be canceled.", "Some schedules will be posted online.", "A pool will be cleaned."], "ans": 2, "ko": "다음 주에 무슨 일이 일어날 것인가? (A) 건축이 완료될 것이다. (B) 지역 사회 강좌가 취소될 것이다. (C) 일정이 온라인에 게시될 것이다. (D) 수영장이 청소될 것이다."}, {"n": 76, "q": "What does the speaker tell the listeners to do?", "opts": ["Pass along some ideas", "Improve a Web site", "Show a membership card", "Sign up for a tour"], "ans": 0, "ko": "화자는 청자들에게 무엇을 하라고 말하는가? (A) 의견을 전달한다. (B) 웹사이트를 개선한다. (C) 회원 카드를 보여준다. (D) 견학을 신청한다."}], "script": [{"sp": "W", "en": "Good morning, and I apologize for rescheduling this tour at the last minute. As you know, it was originally planned for yesterday, but electricity in the building had to be temporarily cut off. So it wasn't safe to walk around. Now, the first part of the new community center I want to show you all is the indoor pool. It'll be used for youth swimming classes. We'll be posting fee information and schedules for those courses on our Web site next week. And . . . um . . . we're hoping to offer other types of classes, too. Please share your suggestions now or after this tour.", "ko": "안녕하세요, 마지막 순간에 투어의 일정을 변경한 것에 대해 사과드립니다. 아시다시피, 이것은 원래 어제로 예정되어 있었지만, 건물의 전기가 일시적으로 차단되어야 했습니다. 그래서 돌아다니기에 안전하지 않았습니다. 지금부터, 제가 여러분 모두에게 보여드리고 싶은 새로운 지역 문화 센터의 첫 번째 부분은 실내 수영장입니다. 그것은 청소년 수영 수업에 사용될 것입니다. 저희는 다음 주에 수업들의 수업료 정보와 일정을 웹사이트에 게시할 것입니다. 그리고… 음… 저희는 다른 종류의 수업들도 제공하고자 합니다. 여러분의 제안들을 지금이나 투어 후에 공유해주십시오."}]}, {"start": 77, "part": 4, "intro": "", "graphic": false, "speakers": "M-Au", "audio": "Test05_77-79.mp3", "qs": [{"n": 77, "q": "What type of product is being advertised?", "opts": ["A digital camera", "An energy-efficient laptop", "A phone accessory", "A portable speaker"], "ans": 2, "ko": "어떤 종류의 제품이 광고되고 있는가?"}, {"n": 78, "q": "What feature makes the product unique?", "opts": ["A carrying case", "A removable battery", "A touchscreen display", "A solar panel"], "ans": 3, "ko": "어떤 특징이 제품을 특별하게 만드는가?"}, {"n": 79, "q": "Why should listeners visit a Web site?", "opts": ["To read some reviews", "To order a special model", "To request express delivery", "To download a coupon"], "ans": 0, "ko": "청자들은 왜 웹사이트를 방문해야 하는가?"}], "script": [{"sp": "M", "en": "There's nothing more frustrating than needing to charge your smartphone when you don't have access to an outlet. Well, try the Renew charger! Our device is different from those of our competitors because it includes a standard cord for charging as well as a built-in solar panel. What's more, we're certain you'll appreciate the Renew's high-quality components and charging efficiency. But don't take our word for it! Visit www.renewcharger.com to read feedback from hundreds of satisfied customers.", "ko": "콘센트를 이용할 수 없을 때 당신의 스마트폰을 충전해야 하는 것보다 더 초조한 것은 없습니다. 자, Renew 충전기를 사용해보십시오! 저희 기기는 내장된 태양 전지판뿐만 아니라 충전을 위한 표준 규격의 코드도 포함하기 때문에 경쟁 업체들의 기기와 다릅니다. 게다가, 저희는 Renew의 고급 부품들과 충전 효율성에 감탄하실 거라고 확신합니다. 하지만 저희의 말을 곧이곧대로 믿지는 마십시오! www.renewcharger.com을 방문하셔서 만족하신 수백 명의 고객들의 의견을 읽어보세요."}]}, {"start": 80, "part": 4, "intro": "", "graphic": false, "speakers": "M-Cn", "audio": "Test05_80-82.mp3", "qs": [{"n": 80, "q": "What will some customer service representatives most likely do in June?", "opts": ["Begin working at a different time", "Move to a new office", "Take part in a session", "Inform clients about a policy"], "ans": 2, "ko": "일부 고객서비스 담당자들은 6월에 무엇을 할 것 같은가?"}, {"n": 81, "q": "What does the speaker mean when he says, \"anything longer than this is not acceptable\"?", "opts": ["Online chat programs will be adopted.", "Additional staff will be hired.", "Employees must become more efficient.", "Shorter breaks must be introduced."], "ans": 1, "ko": "화자는 \"그보다 더 긴 것은 허용할 수 없습니다\"라고 말할 때 무엇을 의도하는가?"}, {"n": 82, "q": "What does the speaker say he will do?", "opts": ["Choose a worker for a duty", "Sign a legal document", "Evaluate some applicants", "Provide some training"], "ans": 0, "ko": "화자는 무엇을 할 것이라고 말하는가?"}], "script": [{"sp": "M", "en": "I'd like us to turn our attention to next month's schedule. In June, half of our customer service representatives will be attending a weeklong workshop. If no preparations are made, customers will be inconvenienced. It's okay if customers have to wait up to 10 minutes to speak to a representative, but anything longer than this is not acceptable. To help us avoid long service delays, our recruitment agency will provide us with a few temporary workers. Regarding that, I'm going to need one of you to conduct training for several hours on May 20. I'll decide who will get this assignment later today.", "ko": "저는 다음 달 일정으로 우리의 관심을 돌려보고자 합니다. 6월에 저희의 고객서비스 담당자들의 절반이 일주일에 걸친 워크숍에 참석할 것입니다. 준비를 하지 않으면, 고객들이 불편을 느낄 것입니다. 고객들이 직원과 이야기하기 위해 10분까지 기다려야 하는 것은 괜찮지만, 그보다 더 긴 것은 허용할 수 없습니다. 우리의 오랜 서비스 지연을 방지할 수 있도록, 채용 업체에서 몇몇의 임시 직원들을 제공해줄 것입니다. 이와 관련하여, 여러분 중 한 분이 5월 20일에 몇 시간 동안 교육을 실시해주셔야 합니다. 저는 누가 이 일을 맡게 될 것인지 오늘 늦게 결정할 것입니다."}]}, {"start": 83, "part": 4, "intro": "", "graphic": false, "speakers": "M-Au", "audio": "Test05_83-85.mp3", "qs": [{"n": 83, "q": "According to the speaker, what can listeners do at the information desk?", "opts": ["Pick up a pamphlet", "View a match list", "Ask about some prizes", "Speak to some judges"], "ans": 1, "ko": "화자에 따르면, 청자들은 안내 데스크에서 무엇을 할 수 있는가?"}, {"n": 84, "q": "Why is Mary O'Reilly unable to attend the tournament?", "opts": ["She does not feel well.", "She missed a flight.", "She is hosting a fund-raiser.", "She is getting ready for a match."], "ans": 0, "ko": "Mary O'Reilly는 왜 토너먼트에 참석할 수 없는가?"}, {"n": 85, "q": "What will be broadcast on WXTC Radio?", "opts": ["Celebrity interviews", "Award recipient names", "Additional program changes", "Details about a competition"], "ans": 3, "ko": "WXTC 라디오에서는 무엇이 방송될 것인가?"}], "script": [{"sp": "M", "en": "Attention all tournament attendees. A list of this afternoon's matches is posted at the information desk near the entrance of Lilly Park. Please note, however, that there is one change to today's program. Famed tennis star Mary O'Reilly, who was supposed to play an exhibition match during the tournament, is unable to join us. She's apparently sick and not able to travel. It's quite unfortunate, as I know many of you were looking forward to meeting Ms. O'Reilly. And as a last reminder, coverage of today's activities and matches will be aired on WXTC Radio, our media partner for the event. You can listen in on 99.7 FM.", "ko": "모든 토너먼트 참가자들은 주목해 주시기 바랍니다. 오늘 오후 경기 목록이 Lilly 공원 입구 근처에 있는 안내 데스크에 게시되었습니다. 하지만 오늘 프로그램에 한 가지 변경 사항이 있다는 것을 유념해 주십시오. 토너먼트 동안 시범 경기를 하기로 되어 있었던 유명한 테니스 스타인 Mary O'Reilly가 저희와 함께하지 못합니다. 듣자 하니 그녀가 아파서 이동할 수 없다고 합니다. 저는 많은 분들께서 Ms. O'Reilly를 만나기를 고대하고 있었다는 것을 알고 있기에 꽤 유감스럽습니다. 그리고 마지막으로 상기시켜 드리는 것은, 오늘의 활동과 경기에 대한 보도는 행사의 미디어 협력업체인 WXTC 라디오에서 방송될 것입니다. 99.7 FM에서 청취하실 수 있습니다."}]}, {"start": 86, "part": 4, "intro": "", "graphic": false, "speakers": "M-Am", "audio": "Test05_86-88.mp3", "qs": [{"n": 86, "q": "What is the radio broadcast mainly about?", "opts": ["The success of an author", "Different formats of publications", "Special events at a bookstore", "A newly developed device"], "ans": 1, "ko": "라디오 방송은 주로 무엇에 관한 것인가?"}, {"n": 87, "q": "What does the speaker mention about Gail Boyd?", "opts": ["She made a past appearance on the show.", "She gives informational talks at schools.", "She will be arriving later than planned.", "She founded her own company."], "ans": 0, "ko": "화자는 Gail Boyd에 관해 무엇을 언급하는가?"}, {"n": 88, "q": "What will happen next?", "opts": ["A guest will describe her work experience.", "A book excerpt will be read.", "A writer will discuss her novel.", "A special report will be aired."], "ans": 0, "ko": "다음에 무슨 일이 일어날 것인가?"}], "script": [{"sp": "M", "en": "Coming up next on Book Talk, we'll be continuing yesterday's discussion on e-books and why some genres are better suited for this digital format than others. For example, mystery and science fiction releases tend to sell well as e-books. But when it comes to photo books and travel guidebooks, readers prefer printed copies. Why is this so? Publishing industry expert Gail Boyd is on our show again and will go over all of this and more. Now, Ms. Boyd, let's begin by having you give us a quick overview of your professional background in publishing.", "ko": "다음 Book Talk에서는, 전자책에 대한 논의와 왜 몇몇 장르들이 다른 것들보다 디지털 형식에 더 잘 맞는지에 대한 어제의 논의를 계속할 것입니다. 예를 들어, 추리 소설과 공상 과학 소설 출간물들은 전자책으로 잘 팔리는 경향이 있습니다. 하지만 화보집과 여행 안내서에 관한 한, 독자들은 인쇄된 책을 선호합니다. 왜 이런 걸까요? 출판업계 전문가인 Gail Boyd는 저희 쇼에 다시 나와서 이 모든 것과 추가적인 것들을 살펴볼 것입니다. 자, Ms. Boyd, 저희에게 출판업계에서의 당신의 경력에 대한 간략한 개요를 알려주시면서 시작해 봅시다."}]}, {"start": 89, "part": 4, "intro": "", "graphic": false, "speakers": "W-Br", "audio": "Test05_89-91.mp3", "qs": [{"n": 89, "q": "What type of gathering is the listener organizing?", "opts": ["A retirement party", "An awards banquet", "A corporate picnic", "A wedding ceremony"], "ans": 1, "ko": "청자는 어떤 종류의 모임을 개최하는가?"}, {"n": 90, "q": "What did the speaker do this morning?", "opts": ["Sent out a revised cost estimate", "Contacted a venue manager", "Added people to a guest list", "Spoke with a chef about a menu"], "ans": 3, "ko": "화자는 오늘 아침에 무엇을 했는가?"}, {"n": 91, "q": "Why does the speaker say, \"There were 300 people at an event we catered yesterday\"?", "opts": ["To make a correction", "To provide a discount", "To explain a request", "To offer assurance"], "ans": 3, "ko": "화자는 왜 \"어제 저희가 음식을 공급한 행사에 300명이 있었습니다\"라고 말하는가?"}], "script": [{"sp": "W", "en": "Mr. Richards, this is Chloe Friedman from Breckendale Catering. I want to thank you for considering our company as you make arrangements for your upcoming music awards dinner. Regarding the message you left me, we're happy to accommodate people with dairy allergies. In fact, I talked to our head chef about the matter this morning, and we came up with a number of great dishes. Finally, you mentioned that you were uncertain about whether a company as small as ours could handle 250 guests. There were 300 people at an event we catered yesterday. If you'd like a specific estimate, I'm available to talk at your convenience.", "ko": "Mr. Richards, 저는 Breckendale 출장 요리업체의 Chloe Friedman입니다. 귀하가 다가오는 음악 시상식 만찬을 준비하시면서 저희 회사를 고려해주신 점에 대해 감사드리고 싶습니다. 귀하께서 남기신 메시지에 대하여, 저희는 유제품 알레르기가 있는 분들에게 기꺼이 맞춰드릴 수 있습니다. 사실, 저는 오늘 아침에 이 문제에 대해 저희 수석 요리사와 이야기했고, 저희는 굉장한 요리들을 많이 생각해냈습니다. 마지막으로, 귀하는 저희와 같은 작은 회사가 250명의 손님을 감당할 수 있는지 확신이 없다고 말씀하셨습니다. 어제 저희가 음식을 공급한 행사에 300명이 있었습니다. 구체적인 견적서를 원하시면, 편하실 때 이야기를 나눌 수 있습니다."}]}, {"start": 92, "part": 4, "intro": "", "graphic": false, "speakers": "M-Au", "audio": "Test05_92-94.mp3", "qs": [{"n": 92, "q": "Where most likely are the listeners?", "opts": ["At a farm", "At a food processing plant", "At a café", "At a research facility"], "ans": 1, "ko": "청자들은 어디에 있는 것 같은가?"}, {"n": 93, "q": "What does the speaker say he will discuss?", "opts": ["The origins of some ingredients", "The uses of some machinery", "The purpose of a project", "The size of an organization"], "ans": 0, "ko": "화자는 그가 무엇을 논의할 것이라고 말하는가?"}, {"n": 94, "q": "What will listeners be able to do at the end of the tour?", "opts": ["View an instructional video", "Meet a business owner", "Make a purchase", "Try a sample"], "ans": 3, "ko": "청자들은 견학 마지막에 무엇을 할 수 있을 것인가?"}], "script": [{"sp": "M", "en": "Welcome to the Preston Coffee roasting factory. My name is Arnold, and I'll be leading you on our tour today. Our first stop will be our storeroom, where I'll explain how we source our beans as well as what countries they come from. After that, we'll head to the main floor to watch the actual roasting process. Finally, we'll return to the administrative office, at which point you'll get a chance to taste our world-famous coffee before going home today. All right, let's get started.", "ko": "Preston 커피 로스팅 공장에 오신 것을 환영합니다. 제 이름은 Arnold이고, 저는 오늘 저희의 견학을 인솔할 것입니다. 저희가 처음으로 둘러볼 곳은 저장실인데, 그곳에서 저는 원두가 어떤 나라에서 생산되는지뿐만 아니라 저희가 어떻게 원두를 공급받는지를 설명할 것입니다. 그 후, 저희는 실제 로스팅 과정을 보기 위해 1층으로 향할 것입니다. 마지막으로, 저희는 행정실로 돌아올 것이고, 그곳에서 여러분들은 오늘 집으로 가시기 전에 세계적으로 유명한 저희의 커피를 맛보는 기회를 얻으실 것입니다. 자, 시작합시다."}]}, {"start": 95, "part": 4, "intro": "", "graphic": true, "speakers": "M-Am", "audio": "Test05_95-97.mp3", "qs": [{"n": 95, "q": "According to the speaker, what did Amanda do?", "opts": ["Met with some customers", "Decorated some conference halls", "Summarized some preparations", "Confirmed a reservation"], "ans": 2, "ko": "화자에 따르면, Amanda는 무엇을 했는가?\n(A) 고객들과 만났다.\n(B) 회의장을 장식했다.\n(C) 준비 과정을 요약했다.\n(D) 예약을 확인했다."}, {"n": 96, "q": "What is mentioned about the speaker's company?", "opts": ["It operates internationally.", "It will partner with another firm.", "It launched a new Web site.", "It is sponsoring a conference."], "ans": 3, "ko": "화자의 회사에 관해 무엇이 언급되는가?\n(A) 국제적으로 운영된다.\n(B) 다른 회사와 협력할 것이다.\n(C) 새로운 웹사이트를 출시했다.\n(D) 학회를 후원하고 있다."}, {"n": 97, "q": "Look at the graphic. Where will the magazine rack be placed this year?", "opts": ["In Space 1", "In Space 2", "In Space 3", "In Space 4"], "ans": 0, "ko": "시각 자료를 보시오. 올해는 잡지 선반이 어디에 놓일 것인가?\n(A) 공간 1에\n(B) 공간 2에\n(C) 공간 3에\n(D) 공간 4에"}], "script": [{"sp": "M", "en": "Amanda, thanks for giving us a summary of what's been done so far to get ready for the Buckley Pharmaceutical Conference. However, one detail still needs to be discussed. Our company is sponsoring the conference once again, which means we're entitled to distribute our magazine to all participants. Last year's event was also at the Astor Conference Center, and we . . . ah . . . set the magazine rack in Seminar Room 1—the room directly across from the stage. However, only 70 copies were taken. That's why we'll be placing the rack in the space beside the stage this year.", "ko": "Amanda, 저희에게 Buckley 제약 학회를 준비하기 위해 지금까지 무엇이 완료되었는지에 대해 요약해 주셔서 감사합니다. 하지만, 한 가지 세부 사항이 여전히 논의되어야 합니다. 저희 회사는 이 학회를 다시 한번 후원하고 있으며, 이는 저희가 모든 참가자들에게 저희의 잡지를 나누어 줄 수 있는 자격이 있음을 의미합니다. 작년 행사 또한 Astor 회의장에서 열렸고, 우리는… 아… 무대의 바로 맞은편에 있는 세미나실 1에 잡지 선반을 설치했었습니다. 하지만, 70부만 가져갔습니다. 그것이 저희가 올해는 선반을 무대 옆 공간에 놓고자 하는 이유입니다."}], "gimg": "hk_t5_g95.jpg"}, {"start": 98, "part": 4, "intro": "", "graphic": true, "speakers": "M-Cn", "audio": "Test05_98-100.mp3", "qs": [{"n": 98, "q": "Look at the graphic. Which category must be modified?", "opts": ["Name", "Staff ID", "Department", "Issue Date"], "ans": 2, "ko": "시각 자료를 보시오. 어떤 항목이 수정되어야 하는가?\n(A) 이름\n(B) 직원 ID\n(C) 부서\n(D) 발급일"}, {"n": 99, "q": "What does the speaker need to do later today?", "opts": ["Fill out some paperwork", "Set up a new desk", "Attend a mandatory event", "Report some accounting errors"], "ans": 2, "ko": "화자는 오늘 늦게 무엇을 해야 하는가?\n(A) 서류를 작성한다.\n(B) 새 책상을 설치한다.\n(C) 필수 행사에 참석한다.\n(D) 계산 오류를 보고한다."}, {"n": 100, "q": "How can the listener ask the speaker a question?", "opts": ["By calling an extension", "By sending an e-mail", "By visiting a workstation", "By leaving a written note"], "ans": 1, "ko": "청자는 어떻게 화자에게 질문할 수 있는가?\n(A) 내선으로 전화함으로써\n(B) 이메일을 보냄으로써\n(C) 작업 장소를 방문함으로써\n(D) 메모를 남김으로써"}], "script": [{"sp": "M", "en": "This message is for Carmen Kimbra. My name is Tyler Porter, and I was told that you're responsible for issuing staff identification badges. I'd like to report an error on the one I just received. According to my badge, I'm a part of the marketing team, but I was actually hired as an accountant. It'd be great if this could be taken care of as soon as possible. Since I'll be at a required orientation session later this afternoon, you won't be able to reach me by phone. So, if you have any questions regarding my request or personal details, please e-mail me, and I'll respond shortly.", "ko": "이 메시지는 Carmen Kimbra를 위한 것입니다. 제 이름은 Tyler Porter이고, 저는 당신이 직원 신분증을 발행하는 것을 담당하신다고 들었습니다. 저는 제가 방금 받은 것에 있는 오류를 보고하고 싶습니다. 제 신분증에는 제가 마케팅팀의 일원으로 되어 있지만, 저는 사실 회계사로 고용되었습니다. 이것이 최대한 빨리 처리될 수 있으면 좋겠습니다. 제가 오늘 오후 늦게 필수 오리엔테이션에 참석할 것이기 때문에, 저에게 전화로 연락하실 수 없을 것입니다. 그러므로, 저의 요청이나 개인적인 세부 사항에 대해 질문이 있으시면 저에게 이메일을 보내주시고, 제가 곧 답변드리겠습니다."}], "gimg": "hk_t5_g98.jpg"}]};
